const body = $json.body ?? {};
const onlyDigits = (value) => String(value ?? '').replace(/\D/g, '');
const normalizeBrazilPhone = (value) => {
  const digits = onlyDigits(value);
  if (digits.length === 10 || digits.length === 11) return `55${digits}`;
  return digits;
};
const msg = String(body.text ?? body.message ?? '').replace(/\s+/g, ' ').trim();
const chatId = normalizeBrazilPhone(body.chat_id ?? body.from ?? body.customer_phone_e164 ?? '');
return {
  tenant_id: body.tenant_id || null,
  tenant_phone_e164: normalizeBrazilPhone(body.tenant_phone_e164 ?? body.to ?? body.receiver ?? ''),
  customer_phone_e164: normalizeBrazilPhone(body.customer_phone_e164 ?? body.from ?? body.chat_id ?? ''),
  chat_id: chatId,
  msg,
  raw_body: body
};

const row = Array.isArray($json) ? $json[0] : $json;
const msg = String($node.Normalize.json.msg ?? '').replace(/\s+/g, ' ').trim();
const customerPhone = String($node.Normalize.json.customer_phone_e164 ?? '').trim();
const payload = row.payload_draft ?? {};
const draft = payload.signup ?? {};
const groups = Array.isArray(row.groups) ? row.groups : [];
const config = row.signup_config ?? {};
const plans = Array.isArray(config.plans) ? config.plans : [];
const step = row.step || 'billing_signup_welcome';
const tenantName = row.tenant_name || 'o professor';

function normalize(value) {
  return String(value ?? '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();
}

function onlyDigits(value) {
  return String(value ?? '').replace(/\D/g, '');
}

function isValidCpf(value) {
  const cpf = onlyDigits(value);
  if (cpf.length !== 11 || /^(\d)\1{10}$/.test(cpf)) return false;
  const digit = (length) => {
    let sum = 0;
    for (let index = 0; index < length; index += 1) {
      sum += Number(cpf[index]) * (length + 1 - index);
    }
    const remainder = (sum * 10) % 11;
    return remainder === 10 ? 0 : remainder;
  };
  return digit(9) === Number(cpf[9]) && digit(10) === Number(cpf[10]);
}

function formatCpf(value) {
  const cpf = onlyDigits(value);
  return cpf.replace(/(\d{3})(\d{3})(\d{3})(\d{2})/, '$1.$2.$3-$4');
}

function parseBirthDate(value) {
  const text = String(value ?? '').trim();
  let day;
  let month;
  let year;
  let match = text.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (match) {
    day = Number(match[1]);
    month = Number(match[2]);
    year = Number(match[3]);
  } else {
    match = text.match(/^(\d{4})-(\d{2})-(\d{2})$/);
    if (!match) return null;
    year = Number(match[1]);
    month = Number(match[2]);
    day = Number(match[3]);
  }

  const birth = new Date(Date.UTC(year, month - 1, day));
  if (birth.getUTCFullYear() !== year || birth.getUTCMonth() !== month - 1 || birth.getUTCDate() !== day) return null;

  const todayParts = Object.fromEntries(
    new Intl.DateTimeFormat('en', {
      timeZone: 'America/Fortaleza',
      year: 'numeric',
      month: '2-digit',
      day: '2-digit'
    }).formatToParts(new Date()).filter((part) => part.type !== 'literal').map((part) => [part.type, Number(part.value)])
  );
  let age = todayParts.year - year;
  if (todayParts.month < month || (todayParts.month === month && todayParts.day < day)) age -= 1;
  if (age < 0 || age > 120) return null;

  return {
    iso: String(year).padStart(4, '0') + '-' + String(month).padStart(2, '0') + '-' + String(day).padStart(2, '0'),
    display: String(day).padStart(2, '0') + '/' + String(month).padStart(2, '0') + '/' + String(year),
    age
  };
}

function formatMoney(cents) {
  return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(Number(cents) / 100);
}

function reply(text, nextStep, patch = {}, close = false) {
  return [{ json: {
    action: 'patch',
    to: customerPhone || draft.customer_whatsapp,
    reply: text,
    conversation_id: row.conversation_id,
    next_step: nextStep,
    p_close: close,
    data_patch: {
      flow_version: 3,
      signup: { ...patch, customer_whatsapp: customerPhone || draft.customer_whatsapp || null },
      metadata: { last_step: nextStep, updated_at: new Date().toISOString() }
    }
  }}];
}

function resolveChoice(value, options) {
  const text = String(value ?? '').trim();
  const leading = text.match(/^(\d+)(?:[.)\s]|$)/);
  if (leading) {
    const selected = options[Number(leading[1]) - 1];
    if (selected) return selected;
  }
  const wanted = normalize(text);
  return options.find((option) => normalize(option.name) === wanted) || null;
}

function renderPlanPrompt() {
  const options = plans.map((plan, index) =>
    String(index + 1) + ') ' + plan.name + ' · ' + formatMoney(plan.amount_cents) + ' · vence dia ' + plan.due_day
  ).join('\n');
  return 'Escolha o plano de mensalidade que combina com você:\n\n' + options;
}

function renderGroupPrompt() {
  const options = groups.map((group, index) =>
    String(index + 1) + ') ' + group.name
  ).join('\n');
  return 'Agora escolha uma turma disponível:\n\n' + options;
}

function renderSummary(values) {
  const billingLabel = values.signup_plan_name || (config.mode === 'fixed' ? 'Mensalidade fixa' : 'Plano escolhido');
  const guardian = values.guardian_full_name
    ? '\nResponsável: ' + values.guardian_full_name + '\nCPF do responsável: ' + formatCpf(values.guardian_cpf)
    : '';
  return 'Confira os dados antes de enviar para ' + tenantName + ':\n\n' +
    'Nome: ' + values.full_name + '\n' +
    'E-mail: ' + values.email + '\n' +
    'CPF: ' + formatCpf(values.cpf) + '\n' +
    'Nascimento: ' + values.birth_date_display + guardian + '\n' +
    'WhatsApp: ' + (customerPhone || values.customer_whatsapp) + '\n' +
    billingLabel + ': ' + formatMoney(values.amount_cents) + '\n' +
    'Vencimento: dia ' + values.due_day + '\n' +
    'Turma: ' + (values.group_name || 'O professor escolherá antes de aprovar') + '\n\n' +
    'Use os botões abaixo para confirmar ou refazer o cadastro.';
}

function nextAfterBilling(values) {
  if (groups.length) return reply(renderGroupPrompt(), 'collect_group', values);
  return reply(renderSummary(values), 'confirm_signup', values);
}

function nextAfterIdentity(values) {
  if (config.mode === 'fixed') {
    return nextAfterBilling({
      ...values,
      signup_plan_id: null,
      signup_plan_name: 'Mensalidade fixa',
      amount_cents: config.fixed_amount_cents,
      due_day: config.fixed_due_day
    });
  }
  return reply(renderPlanPrompt(), 'collect_signup_plan', values);
}

function createSignup() {
  const notes = draft.group_name
    ? 'Turma escolhida no WhatsApp: ' + draft.group_name + '. O professor poderá alterá-la antes da aprovação.'
    : 'Cadastro solicitado pelo WhatsApp, sem turma definida.';
  return [{ json: {
    action: 'create',
    to: customerPhone || draft.customer_whatsapp,
    conversation_id: row.conversation_id,
    next_step: 'billing_signup_done',
    p_close: true,
    create_body: {
      p_tenant_id: row.tenant_id,
      p_full_name: draft.full_name,
      p_whatsapp_e164: customerPhone || draft.customer_whatsapp,
      p_email: draft.email,
      p_cpf: draft.cpf,
      p_birth_date: draft.birth_date,
      p_guardian_full_name: draft.guardian_full_name || null,
      p_guardian_cpf: draft.guardian_cpf || null,
      p_group_id: draft.group_id || null,
      p_group_name: draft.group_name || null,
      p_signup_plan_id: draft.signup_plan_id || null,
      p_notes: notes
    },
    data_patch: {
      flow_version: 3,
      signup: { ...draft, customer_whatsapp: customerPhone || draft.customer_whatsapp || null },
      metadata: { completed_at: new Date().toISOString() }
    }
  }}];
}

if (step === 'billing_signup_disabled' || step === 'billing_signup_configuration_missing') {
  const unavailable = String(row.welcome_message || '').replaceAll('{{tenant_name}}', tenantName);
  return reply(unavailable, step, {});
}

if (['menu', 'inicio', 'iniciar', 'recomecar', 'refazer cadastro'].includes(normalize(msg)) || step === 'billing_signup_welcome') {
  const welcome = String(row.welcome_message || '').replaceAll('{{tenant_name}}', tenantName);
  return reply(welcome, 'collect_full_name', {});
}

if (!msg) return reply('Não consegui ler sua mensagem. Pode enviá-la novamente, por favor?', step, draft);

if (step === 'collect_full_name') {
  const fullName = msg.replace(/\s+/g, ' ').trim();
  if (fullName.split(' ').filter(Boolean).length < 2) {
    return reply('Por favor, envie seu nome completo. Exemplo: Maria da Silva.', step, draft);
  }
  return reply('Qual é o seu e-mail?', 'collect_email', { ...draft, full_name: fullName });
}

if (step === 'collect_email') {
  const email = msg.toLowerCase().trim();
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(email)) {
    return reply('Não consegui validar esse e-mail. Envie no formato nome@exemplo.com.', step, draft);
  }
  return reply('Agora envie seu CPF.', 'collect_cpf', { ...draft, email });
}

if (step === 'collect_cpf') {
  const cpf = onlyDigits(msg);
  if (!isValidCpf(cpf)) {
    return reply('Esse CPF não parece válido. Confira os 11 números e envie novamente.', step, draft);
  }
  return reply('Qual é a sua data de nascimento? Envie no formato DD/MM/AAAA.', 'collect_birth_date', { ...draft, cpf });
}

if (step === 'collect_birth_date') {
  const birth = parseBirthDate(msg);
  if (!birth) {
    return reply('Não consegui validar essa data. Envie no formato DD/MM/AAAA.', step, draft);
  }
  const withBirth = {
    ...draft,
    birth_date: birth.iso,
    birth_date_display: birth.display,
    is_under_14: birth.age < 14
  };
  if (birth.age < 14) {
    return reply('Como o aluno tem menos de 14 anos, envie o nome completo do responsável.', 'collect_guardian_name', withBirth);
  }
  return nextAfterIdentity({
    ...withBirth,
    guardian_full_name: null,
    guardian_cpf: null
  });
}

if (step === 'collect_guardian_name') {
  const guardianName = msg.replace(/\s+/g, ' ').trim();
  if (guardianName.split(' ').filter(Boolean).length < 2) {
    return reply('Envie o nome completo do responsável. Exemplo: Ana Maria da Silva.', step, draft);
  }
  return reply('Agora envie o CPF do responsável.', 'collect_guardian_cpf', { ...draft, guardian_full_name: guardianName });
}

if (step === 'collect_guardian_cpf') {
  const guardianCpf = onlyDigits(msg);
  if (!isValidCpf(guardianCpf)) {
    return reply('Esse CPF não parece válido. Confira os 11 números e envie novamente.', step, draft);
  }
  return nextAfterIdentity({ ...draft, guardian_cpf: guardianCpf });
}

if (step === 'collect_signup_plan') {
  const selected = resolveChoice(msg, plans);
  if (!selected) return reply('Não identifiquei esse plano.\n\n' + renderPlanPrompt(), step, draft);
  return nextAfterBilling({
    ...draft,
    signup_plan_id: selected.id,
    signup_plan_name: selected.name,
    amount_cents: selected.amount_cents,
    due_day: selected.due_day
  });
}

if (step === 'collect_group') {
  const answer = normalize(msg);
  const leading = String(msg).trim().match(/^(\d+)(?:[.)\s]|$)/);
  const leaveForTeacher = leading?.[1] === '0' || ['professor seleciona', 'deixar para o professor', 'nenhum', 'nenhuma', 'nao sei'].includes(answer);
  const selected = leaveForTeacher ? null : resolveChoice(msg, groups);
  if (!leaveForTeacher && !selected) return reply('Não identifiquei essa turma.\n\n' + renderGroupPrompt(), step, draft);
  const merged = {
    ...draft,
    group_id: selected?.id || null,
    group_name: selected?.name || null
  };
  return reply(renderSummary(merged), 'confirm_signup', merged);
}

if (step === 'confirm_signup') {
  const answer = normalize(msg);
  if (['recomecar', 'refazer', 'refazer cadastro'].includes(answer)) {
    const welcome = String(row.welcome_message || '').replaceAll('{{tenant_name}}', tenantName);
    return reply(welcome, 'collect_full_name', {});
  }
  if (!['sim', 's', 'confirmar', 'confirmo', 'confirmar cadastro'].includes(answer)) {
    return reply(renderSummary(draft), step, draft);
  }
  return createSignup();
}

const welcome = String(row.welcome_message || '').replaceAll('{{tenant_name}}', tenantName);
return reply(welcome, 'collect_full_name', {});

const original = $node.FN_signup_state_machine.json;
const data = Array.isArray($json) ? $json[0] : $json;
let reply = 'Cadastro enviado! 😊\n\nO professor recebeu seus dados e poderá revisar a turma antes da aprovação. Depois que ele aprovar, seu cadastro e sua mensalidade aparecerão no sistema.';
let nextStep = 'billing_signup_pending_approval';
if (data.request_status === 'cpf_already_registered') {
  reply = 'Este CPF já está cadastrado. Para consultar ou atualizar os dados do aluno, fale com a equipe do professor pelo atendimento humano.';
  nextStep = 'billing_signup_duplicate_cpf';
} else if (data.request_status === 'cpf_already_pending') {
  reply = 'Já existe um cadastro com este CPF aguardando a análise do professor. Não é necessário enviar os dados novamente.';
  nextStep = 'billing_signup_duplicate_cpf';
}
return [{ json: {
  to: original.to,
  reply,
  conversation_id: original.conversation_id,
  next_step: nextStep,
  p_close: true,
  data_patch: {
    ...original.data_patch,
    signup: {
      ...original.data_patch.signup,
      request_id: data.request_id,
      request_status: data.request_status
    },
    metadata: { submitted_at: new Date().toISOString(), request_status: data.request_status }
  }
}}];
